package com.vidaysalud.veterinaria.pagoservicio.service;import com.vidaysalud.veterinaria.pagoservicio.client.ConsultaClient;import com.vidaysalud.veterinaria.pagoservicio.dto.*;import com.vidaysalud.veterinaria.pagoservicio.exception.*;import com.vidaysalud.veterinaria.pagoservicio.model.*;import com.vidaysalud.veterinaria.pagoservicio.repository.PagoRepository;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.LocalDateTime;import java.util.*;@Service @RequiredArgsConstructor @Transactional public class PagoService{private final PagoRepository r;private final ConsultaClient c;@Transactional(readOnly=true)public List<PagoResponseDTO>listar(){return r.findAll().stream().map(this::dto).toList();}@Transactional(readOnly=true)public PagoResponseDTO buscar(Integer id){return dto(get(id));}public PagoResponseDTO crear(PagoRequestDTO d){c.validar(d.getIdConsulta());r.findByIdConsulta(d.getIdConsulta()).ifPresent(x->{throw new DatoDuplicadoException("La consulta ya posee un pago");});Pago p=map(new Pago(),d);return dto(r.save(p));}public PagoResponseDTO actualizar(Integer id,PagoRequestDTO d){Pago p=get(id);if(!p.getIdConsulta().equals(d.getIdConsulta())){c.validar(d.getIdConsulta());r.findByIdConsulta(d.getIdConsulta()).ifPresent(x->{throw new DatoDuplicadoException("La consulta ya posee un pago");});}return dto(r.save(map(p,d)));}public PagoResponseDTO estado(Integer id,EstadoPago e){Pago p=get(id);if(p.getEstado()==EstadoPago.ANULADO&&e==EstadoPago.PAGADO)throw new ReglaNegocioException("Un pago anulado no puede marcarse como pagado");p.setEstado(e);p.setFechaPago(e==EstadoPago.PAGADO?LocalDateTime.now():null);return dto(r.save(p));}public void eliminar(Integer id){r.delete(get(id));}private Pago get(Integer id){return r.findById(id).orElseThrow(()->new RecursoNoEncontradoException("Pago no encontrado: "+id));}private Pago map(Pago p,PagoRequestDTO d){p.setIdConsulta(d.getIdConsulta());p.setMonto(d.getMonto());p.setMetodoPago(d.getMetodoPago());p.setEstado(d.getEstado()==null?EstadoPago.PENDIENTE:d.getEstado());p.setReferencia(d.getReferencia());if(p.getEstado()==EstadoPago.PAGADO&&p.getFechaPago()==null)p.setFechaPago(LocalDateTime.now());return p;}private PagoResponseDTO dto(Pago p){return PagoResponseDTO.builder().idPago(p.getIdPago()).idConsulta(p.getIdConsulta()).monto(p.getMonto()).metodoPago(p.getMetodoPago()).estado(p.getEstado()).fechaPago(p.getFechaPago()).referencia(p.getReferencia()).build();}}